1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUM: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	  rune: 25,
9	};
10	
11	type Item = { type: string };
12	type QuoteStep = { op: "quote"; items: Item[] };
13	type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
14	
15	const basePremiumFor = (item: Item) => BASE_PREMIUM[item.type];
16	
17	const sumBasePremiums = (items: Item[]) =>
18	  items.reduce((sum, item) => sum + basePremiumFor(item), 0);
19	
20	const quote = (step: QuoteStep) => ({
21	  premium: sumBasePremiums(step.items) + PROCESSING_FEE,
22	});
23	
24	export const run = (input: Scenario): unknown => {
25	  return { results: input.steps.map(quote) };
26	};
