23	    const result = run({
24	      customer: { yearsWithMHPCO: 0 },
25	      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
26	    });
27	    expect(result).toEqual({ results: [{ premium: 65 }] });
28	  });
29	  it("quote single staff → 80 G base + 5 fee = 85 G", () => {
30	    const result = run({
31	      customer: { yearsWithMHPCO: 0 },
