52	  it.todo("quote single moonstone → 25 G base + 5 fee = 30 G");
53	
54	  // Block of 3 alike components
55	  it.todo("quote 2 runes → 50 G base + 5 fee = 55 G");
56	  it.todo("quote 3 runes → 60 G base (block) + 5 fee = 65 G");
57	  it.todo("quote 4 runes → 100 G base (no block, requires exactly 3) + 5 fee = 105 G");
58	  it.todo("quote 7 runes → 175 G base + 5 fee = 180 G");
59	
60	  // Alike components — different types do not form a block together
61	  it.todo("quote 2 runes + 1 moonstone → 75 G base + 5 fee = 80 G");
62	  it.todo("quote 3 runes + 3 moonstones → 120 G base (two separate blocks) + 5 fee = 125 G");
63	
64	  // Item-specific modifiers: cursed surcharge applies to the cursed item only
65	  it.todo("quote cursed sword on item-only scope → 100 + 50 curse + 5 fee = 155 G");
