68	  it.todo("quote sword enchantment 5 → 100 + 30 high-enchant + 5 fee = 135 G (threshold)");
69	  it.todo("quote sword enchantment 4 → 100 + 5 fee = 105 G (below threshold)");
70	  it.todo("quote cursed sword enchantment 5 → 100 + 50 + 30 + 5 = 185 G");
