72	  // Policy-wide modifiers
73	  it.todo("quote cursed sword + plain amulet → 160 base + 50 curse + 5 fee = 215 G");
74	  it.todo("quote single sword with customer 2 years → 100 - 20 loyalty + 5 fee = 85 G (threshold)");
